#include<bits/stdc++.h>
using namespace std;
int n;
long long a[200010],b[200010];
long long f[200010][21],g[200010][21],ans=LLONG_MAX;
vector<pair<int,int>> mp[200010];
void dfs(int x)
{
    int lson=x*2,rson=x*2+1,fa=x/2;
    if(lson>n)
    {
        long long sum=0;
        for(int p=x,i=0;i<=18;i++)
        {
            sum+=b[p];
            f[x][i]=(sum+b[p^1])*a[p^1];
            p/=2;
            g[x][i]=sum*a[p];
        }
        return;
    }
    if(lson==n)
    {
        dfs(lson);
        for(int i=0;i<=18;i++)
        {
            f[x][i]=a[lson]*b[lson]+f[lson][i+1];
            g[x][i]=a[lson]*b[lson]+f[lson][i+1];
        }
        g[x][0]=min(g[x][0],g[lson][1]);
        return;
    }
    dfs(lson);
    dfs(rson);
    for(int i=0;i<=18;i++)
    {
        f[x][i]=min(a[lson]*b[lson]+f[lson][0]+f[rson][i+1],a[rson]*b[rson]+f[rson][0]+f[lson][i+1]);
        g[x][i]=min(a[lson]*b[lson]+f[lson][0]+g[rson][i+1],a[rson]*b[rson]+f[rson][0]+g[lson][i+1]);
    }
    g[x][0]=min({g[x][0],a[lson]*b[lson]+g[rson][0]+g[lson][1],a[rson]*b[rson]+g[lson][0]+g[rson][1]});
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(int i=2;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    dfs(1);
    printf("%lld",g[1][0]);
    return 0;
}
